import { createContext, useContext, useState, useEffect } from "react";
import { authService } from "../services/authService.js";

const AuthContext = createContext(null);

export const AuthProvider = ({ children }) => {
const [user, setUser] = useState(null);
const [loading, setLoading] = useState(true);

// Restore user from localStorage
useEffect(() => {
const stored = localStorage.getItem("collabboard_user");
if (stored) setUser(JSON.parse(stored));
setLoading(false);
}, []);

const login = async (email, password) => {
const data = await authService.login(email, password);

```
setUser(data);
localStorage.setItem("collabboard_user", JSON.stringify(data));

return data;
```

};

const register = async (name, email, password) => {
const data = await authService.register(name, email, password);

```
setUser(data);
localStorage.setItem("collabboard_user", JSON.stringify(data));

return data;
```

};

const logout = () => {
setUser(null);
localStorage.removeItem("collabboard_user");
};

const updateUser = (updated) => {
setUser(updated);
localStorage.setItem("collabboard_user", JSON.stringify(updated));
};

// Handle Google OAuth callback
useEffect(() => {
const urlParams = new URLSearchParams(window.location.search);

const token = urlParams.get("token");
const name = urlParams.get("name");
const email = urlParams.get("email");
const avatar = urlParams.get("avatar");

if (token && !user) {
  try {
    const payload = JSON.parse(atob(token.split(".")[1]));

    const userData = {
      _id: payload.id,
      token,
      name,
      email,
      avatar,
    };

    updateUser(userData);

    // Clean URL
    window.history.replaceState({}, document.title, window.location.pathname);

  } catch (err) {
    console.error("Invalid Google token", err);
  }
}

}, [user]);

return (
<AuthContext.Provider
value={{ user, loading, login, register, logout, updateUser }}
>
{children}
</AuthContext.Provider>
);
};

// Custom hook
export const useAuth = () => {
const ctx = useContext(AuthContext);
if (!ctx) throw new Error("useAuth must be used inside AuthProvider");
return ctx;
};

import { createContext, useContext, useEffect, useRef, useState } from "react";
import { io } from "socket.io-client";
import { useAuth } from "./AuthContext.jsx";

const SocketContext = createContext(null);

export const SocketProvider = ({ children }) => {
  const { user }      = useAuth();
  const socketRef     = useRef(null);
  const [connected, setConnected] = useState(false);

  useEffect(() => {
    // Only connect if user is logged in
    if (!user) return;

    socketRef.current = io(import.meta.env.VITE_SOCKET_URL, {
      auth: { token: user.token },
      transports: ["websocket"],
    });

    socketRef.current.on("connect", () => {
      console.log("≡ƒöî Socket connected");
      setConnected(true);
    });

    socketRef.current.on("disconnect", () => {
      console.log("Γ¥î Socket disconnected");
      setConnected(false);
    });

    return () => {
      socketRef.current?.disconnect();
    };
  }, [user]);

  const emit = (event, data) => {
    socketRef.current?.emit(event, data);
  };

  const on = (event, callback) => {
    socketRef.current?.on(event, callback);
  };

  const off = (event, callback) => {
    socketRef.current?.off(event, callback);
  };

  return (
    <SocketContext.Provider value={{ socket: socketRef.current, connected, emit, on, off }}>
      {children}
    </SocketContext.Provider>
  );
};

export const useSocket = () => {
  const ctx = useContext(SocketContext);
  if (!ctx) throw new Error("useSocket must be used inside SocketProvider");
  return ctx;
};

import { createContext, useContext, useState, useEffect } from "react";

const ThemeContext = createContext(null);

export const ThemeProvider = ({ children }) => {
  const [theme, setTheme] = useState(
    () => localStorage.getItem("collabboard_theme") || "light"
  );

  useEffect(() => {
    localStorage.setItem("collabboard_theme", theme);
    document.documentElement.setAttribute("data-theme", theme);
  }, [theme]);

  const toggleTheme = () => setTheme(t => t === "light" ? "dark" : "light");

  return (
    <ThemeContext.Provider value={{ theme, toggleTheme }}>
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = () => useContext(ThemeContext);

