import { useState, useEffect, useRef } from "react";
import { roomService } from "../services/roomService.js";
import { formatTime } from "../utils/formatters.js";
import toast from "react-hot-toast";

export const stringToColor = (str) => {
    const colors = ["#8B5CF6", "#EC4899", "#F97316", "#06B6D4", "#22C55E", "#EF4444"];
    let hash = 0;
    for (let i = 0; i < str.length; i++) hash = str.charCodeAt(i) + ((hash << 5) - hash);
    return colors[Math.abs(hash) % colors.length];
};

export default function useWhiteboardRoom({ roomId }) {
    const [roomInfo, setRoomInfo] = useState(null);
    const [messages, setMessages] = useState([]);
    const [onlineUsers, setOnlineUsers] = useState([]);
    const [typing, setTyping] = useState("");
    const typingTimer = useRef(null);

    const loadRoomData = async () => {
        try {
            const [room, msgs] = await Promise.all([
                roomService.getRoomById(roomId),
                roomService.getMessages(roomId),
            ]);
            setRoomInfo(room);
            const formatted = msgs.map(m => ({
                id: m._id,
                type: m.type,
                user: m.senderId?.name || "Unknown",
                color: stringToColor(m.senderId?.name || ""),
                text: m.text,
                fileName: m.fileName,
                fileUrl: m.fileUrl,
                time: formatTime(m.createdAt),
            }));
            setMessages(formatted);
        } catch (err) {
            toast.error("Could not load room data");
        }
    };

    useEffect(() => {
        loadRoomData();
    }, [roomId]);

    return {
        roomInfo,
        messages, setMessages,
        onlineUsers, setOnlineUsers,
        typing, setTyping,
        typingTimer, stringToColor
    };
}

import { useEffect, useState } from "react";
import { useNavigate }         from "react-router-dom";
import { useRoom }             from "../hooks/useRoom.js";
import { useAuth }             from "../context/AuthContext.jsx";
import Navbar                  from "../components/common/Navbar.jsx";
import { formatDate }          from "../utils/formatters.js";
import {
  Plus, LogIn as LogInIcon, Search, Clock, Users, Star,
  MoreHorizontal, Trash2, Copy, ExternalLink, X,
  Zap, Lock, Globe, ChevronRight, Layers, TrendingUp, BookOpen
} from "lucide-react";
import toast from "react-hot-toast";

export default function DashboardPage() {
  const { rooms, loading, fetchRooms, createRoom, joinRoom, deleteRoom } = useRoom();
  const { user }   = useAuth();
  const navigate   = useNavigate();

  const [search,     setSearch]     = useState("");
  const [filter,     setFilter]     = useState("all");
  const [showCreate, setShowCreate] = useState(false);
  const [showJoin,   setShowJoin]   = useState(false);
  const [newName,    setNewName]    = useState("");
  const [newPrivate, setNewPrivate] = useState(false);
  const [joinId,     setJoinId]     = useState("");
  const [menuOpen,   setMenuOpen]   = useState(null);
  const [starred,    setStarred]    = useState([]);
  const [creating,   setCreating]   = useState(false);
  const [joining,    setJoining]    = useState(false);

  useEffect(() => { fetchRooms(); }, []);

  const filtered = rooms.filter(r =>
    r.name.toLowerCase().includes(search.toLowerCase()) &&
    (filter === "all" || r.isActive)
